package de.drremote.dsp408controller.core.net; import java.io.ByteArrayOutputStream; import java.io.EOFException; import java.io.IOException; import java.io.PushbackInputStream; import java.util.Arrays; public final class DspFrameCodec { private static final int DLE = 0x10; private static final int STX = 0x02; private static final int ETX = 0x03; private DspFrameCodec() { } public static byte[] encode(byte[] payload) { ByteArrayOutputStream body = new ByteArrayOutputStream(); body.write(DLE); body.write(STX); body.writeBytes(payload); body.write(DLE); body.write(ETX); byte[] withoutChecksum = body.toByteArray(); int checksum = 0; for (byte b : withoutChecksum) { checksum ^= (b & 0xFF); } ByteArrayOutputStream frame = new ByteArrayOutputStream(); frame.writeBytes(withoutChecksum); frame.write(checksum & 0xFF); return frame.toByteArray(); } public static DecodedFrame readFrame(PushbackInputStream in) throws IOException { while (true) { int b = in.read(); if (b < 0) { throw new EOFException("EOF before frame start"); } if (b != DLE) { continue; } int next = in.read(); if (next < 0) { throw new EOFException("EOF after DLE"); } if (next == STX) { break; } in.unread(next); } ByteArrayOutputStream afterStart = new ByteArrayOutputStream(); int prev = -1; while (true) { int current = in.read(); if (current < 0) { throw new EOFException("EOF inside frame"); } afterStart.write(current); if (prev == DLE && current == ETX) { break; } prev = current; } int receivedChecksum = in.read(); if (receivedChecksum < 0) { throw new EOFException("EOF while reading checksum byte"); } byte[] afterStartBytes = afterStart.toByteArray(); if (afterStartBytes.length < 2) { throw new IOException("Invalid frame: missing ETX"); } byte[] payload = Arrays.copyOf(afterStartBytes, afterStartBytes.length - 2); ByteArrayOutputStream withoutChecksum = new ByteArrayOutputStream(); withoutChecksum.write(DLE); withoutChecksum.write(STX); withoutChecksum.writeBytes(afterStartBytes); int calculated = 0; for (byte b : withoutChecksum.toByteArray()) { calculated ^= (b & 0xFF); } return new DecodedFrame( payload, calculated == (receivedChecksum & 0xFF), calculated, receivedChecksum ); } public record DecodedFrame(byte[] payload, boolean checksumValid, int calculatedChecksum, int receivedChecksum) { } }